changeSet.sql:
CREATE TABLE IF NOT EXISTS recordings ( id uuid NOT NULL, creation_timestamp timestamp with time zone NOT NULL, file_path varchar(16384), file_creation_timestamp timestamp with time zone NOT NULL, cam_id varchar(255), record_date date NOT NULL, record_time time(0) without time zone NOT NULL, record_timestamp timestamp with time zone NOT NULL, start_processing_timestamp timestamp with time zone, process_timestamp timestamp with time zone, process_attempts integer NOT NULL, detections_count integer NOT NULL, analyze_time integer NOT NULL, analyzed_frames_count integer NOT NULL,
constraint PK_RECORDINGS primary key (id) );
CREATE INDEX IF NOT EXISTS idx_recordings_creation_timestamp ON recordings USING btree (creation_timestamp); CREATE INDEX IF NOT EXISTS idx_recordings_file_creation_timestamp ON recordings USING btree (file_creation_timestamp); CREATE INDEX IF NOT EXISTS idx_recordings_record_timestamp ON recordings USING btree (record_timestamp); CREATE UNIQUE INDEX IF NOT EXISTS udx_export_recordings_file_path ON recordings USING btree (file_path);

CREATE TABLE IF NOT EXISTS detections ( id uuid NOT NULL, creation_timestamp timestamp with time zone NOT NULL, recording_id uuid NOT NULL, detection_timestamp timestamp with time zone NOT NULL, frame_index integer NOT NULL, model varchar(255) NOT NULL, class_id integer NOT NULL, class_name varchar(255) NOT NULL, confidence real NOT NULL, x1 real NOT NULL, y1 real NOT NULL, x2 real NOT NULL, y2 real NOT NULL,
constraint PK_DETECTIONS primary key (id), constraint FK_DETECTIONS_RECORDING foreign key (recording_id) references recordings (id) on delete cascade );
CREATE INDEX IF NOT EXISTS idx_detections_creation_timestamp ON detections USING btree (creation_timestamp);
CREATE INDEX IF NOT EXISTS idx_detections_recording_id ON detections USING btree (recording_id);
CREATE INDEX IF NOT EXISTS idx_detections_detection_timestamp ON detections USING btree (detection_timestamp);
CREATE INDEX IF NOT EXISTS idx_detections_recording_frame ON detections USING btree (recording_id, frame_index);

CREATE TABLE IF NOT EXISTS telegram_users (
    id uuid NOT NULL,
    username varchar(255) NOT NULL,
    chat_id bigint,
    user_id bigint,
    first_name varchar(255),
    last_name varchar(255),
    status varchar(20) NOT NULL,
    creation_timestamp timestamp with time zone NOT NULL,
    activation_timestamp timestamp with time zone,

    constraint PK_TELEGRAM_USERS primary key (id)
);

CREATE UNIQUE INDEX IF NOT EXISTS udx_telegram_users_username
    ON telegram_users USING btree (username);

CREATE UNIQUE INDEX IF NOT EXISTS udx_telegram_users_chat_id
    ON telegram_users USING btree (chat_id);

CREATE UNIQUE INDEX IF NOT EXISTS udx_telegram_users_user_id
    ON telegram_users USING btree (user_id);

CREATE INDEX IF NOT EXISTS idx_telegram_users_status
    ON telegram_users USING btree (status);
